const wiki = (slug: string) => `https://en.wikipedia.org/wiki/${slug}`;

const p = (name: string, description: string, slug?: string): Suggestion => ({
  name,
  description,
  wikipediaUrl: wiki(slug ?? name.replace(/ /g, '_')),
});

